export const useGetCrimsonActionPage = ({
  accountId,
}: {
  accountId?: string;
}): {
  actionPage?: PublicActionPage;
  error: IErrorResponse | undefined | null;
  isError: boolean;
  isFetched: boolean;
  isLoading: boolean;
} => {
